// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

contract FundPoolManager {
    address private _owner;
    mapping(address => address) private _pools;

    event PoolAdded(address indexed pool, address indexed rewardToken);
    event PoolRemoved(address indexed pool);
    event TransferExecuted(address indexed to, uint256 amount);
    event FundRescued(address indexed to, uint256 amount);

    modifier onlyOwner() {
        require(msg.sender == _owner, "Ownable: caller is not the owner");
        _;
    }

    constructor() {
        _owner = msg.sender;
    }

    function pools(address pool) public view returns (address) {
        return _pools[pool];
    }

    function addPool(address pool, address rewardToken) public onlyOwner {
        require(pool != address(0), "Invalid pool address");
        require(_pools[pool] == address(0), "Pool already exists");
        _pools[pool] = rewardToken;
        emit PoolAdded(pool, rewardToken);
    }

    function removePool(address pool) public onlyOwner {
        require(_pools[pool] != address(0), "Pool does not exist");
        delete _pools[pool];
        emit PoolRemoved(pool);
    }

    function transferTo(address payable to, uint256 amount) external {
        require(to != address(0), "Invalid recipient address");
        require(_pools[msg.sender] != address(0), "Unauthorized pool");
        require(address(this).balance >= amount, "Insufficient balance");
        (bool sent,) = to.call{value: amount}("");
        require(sent, "Transfer failed");
        emit TransferExecuted(to, amount);
    }

    function rescueFund(address payable to, uint256 amount) public onlyOwner {
        require(to != address(0), "Invalid recipient address");
        require(address(this).balance >= amount, "Insufficient balance");
        (bool sent,) = to.call{value: amount}("");
        require(sent, "Transfer failed");
        emit FundRescued(to, amount);
    }

    receive() external payable {}

}
